import{_ as t,o,c as r,a3 as a}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Getting Started with Notely","description":"Install Notely, open your first workspace, and understand the key concepts in under 5 minutes.","frontmatter":{"title":"Getting Started with Notely","description":"Install Notely, open your first workspace, and understand the key concepts in under 5 minutes.","keywords":"install, setup, workspace, first launch, getting started","category":"Getting Started"},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1784606116000}'),n={name:"getting-started/index.md"};function i(s,e,l,d,c,p){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Notely is a desktop Markdown notes app for Windows. Your notes live as plain <code>.md</code> files in a folder of your choice — no accounts required, no cloud lock-in.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Details</th></tr></thead><tbody><tr><td><strong>Platform</strong></td><td>Windows 10 / 11 (x64)</td></tr><tr><td><strong>Storage</strong></td><td>~120 MB for the application</td></tr><tr><td><strong>Network</strong></td><td>Not required for core features</td></tr><tr><td><strong>Git</strong></td><td>Optional — required only for Git features</td></tr></tbody></table><h2 id="download-install" tabindex="-1">Download &amp; Install <a class="header-anchor" href="#download-install" aria-label="Permalink to &quot;Download &amp; Install&quot;">​</a></h2><ol><li>Go to the <a href="https://github.com/WGLabz/notely/releases/latest" target="_blank" rel="noreferrer">latest release on GitHub</a>.</li><li>Download the portable <code>.exe</code> file.</li><li>Run it — no installer needed.</li></ol><div class="tip custom-block"><p class="custom-block-title">Portable App</p><p>Notely is a portable executable. You can run it from any folder, including a USB drive or a synced folder.</p></div><h2 id="release-types" tabindex="-1">Release Types <a class="header-anchor" href="#release-types" aria-label="Permalink to &quot;Release Types&quot;">​</a></h2><p>When downloading or building Notely, three package formats are available. Choose the one that fits your workflow:</p><h3 id="_1-nsis-installer-exe" tabindex="-1">1. NSIS Installer (<code>.exe</code>) <a class="header-anchor" href="#_1-nsis-installer-exe" aria-label="Permalink to &quot;1. NSIS Installer (`.exe`)&quot;">​</a></h3><p>A standard Windows installer that installs Notely on your system, creates Start Menu/desktop shortcuts, and registers file associations.</p><ul><li><strong>Best for:</strong> Long-term installations on a single personal or work computer.</li><li><strong>Pros:</strong> Standard user experience, clean updates, easy shortcut access.</li></ul><h3 id="_2-portable-executable-exe" tabindex="-1">2. Portable Executable (<code>.exe</code>) <a class="header-anchor" href="#_2-portable-executable-exe" aria-label="Permalink to &quot;2. Portable Executable (`.exe`)&quot;">​</a></h3><p>A single self-contained application file that runs immediately without installation.</p><ul><li><strong>Best for:</strong> Quick testing, running from a USB drive, or on locked-down environments (e.g. corporate laptops) where administrator/install permissions are restricted.</li><li><strong>Pros:</strong> Zero-install footprint; doesn&#39;t alter system files.</li></ul><h3 id="_3-zip-archive-zip" tabindex="-1">3. ZIP Archive (<code>.zip</code>) <a class="header-anchor" href="#_3-zip-archive-zip" aria-label="Permalink to &quot;3. ZIP Archive (`.zip`)&quot;">​</a></h3><p>A compressed folder containing the compiled application files and dependencies.</p><ul><li><strong>Best for:</strong> Portable configurations where you want full control over where the application files are kept, or for offline distribution.</li><li><strong>Pros:</strong> Easy to inspect files directly; runs without installation.</li></ul><hr><h2 id="cons-limitations-of-packaged-electron-applications" tabindex="-1">Cons &amp; Limitations of Packaged Electron Applications <a class="header-anchor" href="#cons-limitations-of-packaged-electron-applications" aria-label="Permalink to &quot;Cons &amp; Limitations of Packaged Electron Applications&quot;">​</a></h2><p>Since Notely is packaged as an Electron desktop application, it inherits a few tradeoffs compared to native Windows apps or web tools:</p><ol><li><strong>Large Package Size:</strong> The bundle includes both Chromium (browser engine) and Node.js runtime, resulting in a download size of over 100MB+ per package.</li><li><strong>Memory Footprint:</strong> Each open window launches separate helper processes for the renderer, main processor, and utility threads. This consumes more RAM compared to light text editors (like Notepad).</li><li><strong>Windows SmartScreen/Signing Warnings:</strong> Unsigned custom builds may trigger Windows Defender SmartScreen warnings on launch. Users will need to click <em>More Info -&gt; Run Anyway</em> to launch the application unless it is signed with a valid Microsoft Developer Certificate.</li><li><strong>Native Bindings (e.g., node-pty):</strong> Notely compiles binary system dependencies (like the embedded terminal interface) specifically for target operating system architectures (x64). These require corresponding C++ runtimes on the host machine.</li></ol><h2 id="open-your-workspace" tabindex="-1">Open Your Workspace <a class="header-anchor" href="#open-your-workspace" aria-label="Permalink to &quot;Open Your Workspace&quot;">​</a></h2><p>A <strong>workspace</strong> is a folder on your computer where your notes live. Notely reads <code>.md</code> files from this folder and its subfolders.</p><p><strong>First launch:</strong></p><ol><li>Open Notely.</li><li>The workspace picker appears automatically.</li><li>Click <strong>Open Workspace</strong> and select a folder.</li><li>Notely loads your notes.</li></ol><p><strong>Subsequent launches:</strong></p><p>Use <strong>File → Open Recent</strong> or the command palette (<code>Ctrl + K</code>) to reopen a recent workspace instantly.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>What it is</th></tr></thead><tbody><tr><td><strong>Workspace</strong></td><td>A folder containing your Markdown notes</td></tr><tr><td><strong>Note</strong></td><td>A single <code>.md</code> file inside the workspace</td></tr><tr><td><strong>Folder</strong></td><td>A subfolder for organizing related notes</td></tr><tr><td><strong>.notes-app</strong></td><td>A hidden folder Notely creates for note history and support data</td></tr></tbody></table><h2 id="what-to-do-next" tabindex="-1">What to Do Next <a class="header-anchor" href="#what-to-do-next" aria-label="Permalink to &quot;What to Do Next&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:1.5rem;"><p><strong>New to Notely?</strong> → <a href="/getting-started/first-note.html">Create your first note</a></p><p><strong>Ready to write?</strong> → <a href="/editor/">Editor overview</a></p><p><strong>Coming from another tool?</strong> → <a href="/editor/markdown-guide.html">Feature Reference</a></p><p><strong>Need Git integration?</strong> → <a href="/git/">Git overview</a></p></div><h2 id="help-at-any-time" tabindex="-1">Help at Any Time <a class="header-anchor" href="#help-at-any-time" aria-label="Permalink to &quot;Help at Any Time&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>F1</code></td><td>Open Help Center (in-app)</td></tr><tr><td><code>Ctrl + /</code></td><td>Open Keyboard Shortcuts</td></tr><tr><td><code>Ctrl + K</code></td><td>Open Command Palette</td></tr><tr><td><code>Ctrl + Shift + F</code></td><td>Search all notes</td></tr></tbody></table>',34)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
